import asyncio

# Graceful shutdown
import signal
import asyncio

_stop_event = asyncio.Event()

def _shutdown():
    _stop_event.set()

loop = asyncio.get_running_loop()
loop.add_signal_handler(signal.SIGTERM, _shutdown)
loop.add_signal_handler(signal.SIGINT, _shutdown)

import time
import socket
